import java.util.Scanner;

public class UserGreeting {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();
        int age = 25;
        System.out.println("Hello, " + name + "!");
        System.out.println("You are " + age + " years old.");
        System.out.println("Java version: " + System.getProperty("java.version"));
        scanner.close();
    }
}

public class JavaPlatformInfo {
    public static void main(String[] args) {
        System.out.println("=== Java Platform Information ===");
        System.out.println("Java Version: " + System.getProperty("java.version"));
        System.out.println("Java Vendor: " + System.getProperty("java.vendor"));
        System.out.println("JVM Name: " + System.getProperty("java.vm.name"));
        System.out.println("OS Name: " + System.getProperty("os.name"));
        System.out.println("OS Architecture: " + System.getProperty("os.arch"));

        Runtime runtime = Runtime.getRuntime();
        long maxMemory = runtime.maxMemory() / (1024 * 1024);
        long totalMemory = runtime.totalMemory() / (1024 * 1024);
        long freeMemory = runtime.freeMemory() / (1024 * 1024);

        System.out.println("\n=== JVM Memory Info ===");
        System.out.println("Max Memory: " + maxMemory + " MB");
        System.out.println("Total Memory: " + totalMemory + " MB");
        System.out.println("Free Memory: " + freeMemory + " MB");
        System.out.println("Available Processors: " + runtime.availableProcessors());
    }
}

import java.util.ArrayList;
import java.util.List;

public class StudentManagement {
    static class Student {
        String name;
        int id;
        double gpa;

        Student(int id, String name, double gpa) {
            this.id = id;
            this.name = name;
            this.gpa = gpa;
        }

        public String toString() {
            return String.format("ID: %d | Name: %-15s | GPA: %.2f", id, name, gpa);
        }
    }

    public static void main(String[] args) {
        List<Student> students = new ArrayList<>();
        students.add(new Student(101, "Alice Johnson", 3.8));
        students.add(new Student(102, "Bob Smith", 3.5));
        students.add(new Student(103, "Carol White", 3.9));
        students.add(new Student(104, "David Brown", 3.2));

        System.out.println("=== Student Records ===");
        for (Student s : students) {
            System.out.println(s);
        }

        double totalGpa = 0;
        for (Student s : students) {
            totalGpa += s.gpa;
        }
        System.out.println("\nAverage GPA: " + String.format("%.2f", totalGpa / students.size()));
    }
}

