public class JavaVersionDetector {
    public static void main(String[] args) {
        String version = System.getProperty("java.version");
        System.out.println("Java Version: " + version);

        int majorVersion;
        if (version.startsWith("1.")) {
            // Old format: 1.8.0_291
            majorVersion = Integer.parseInt(version.substring(2, 3));
        } else {
            // New format: 17.0.1
            majorVersion = Integer.parseInt(version.split("\\.")[0]);
        }

        System.out.println("Major Version: " + majorVersion);

        String status;
        if (majorVersion < 8) {
            status = "Legacy Java (< 8) - Unsupported";
        } else if (majorVersion <= 16) {
            status = "Modern Java (8-16)";
        } else {
            status = "Latest Java (17+) - LTS Release";
        }
        System.out.println("Status: " + status);
    }
}

public class PlatformReport {
    public static void main(String[] args) {
        Runtime rt = Runtime.getRuntime();
        long totalMB = rt.totalMemory() / (1024 * 1024);
        long freeMB = rt.freeMemory() / (1024 * 1024);
        long usedMB = totalMB - freeMB;

        String os = System.getProperty("os.name");
        String arch = System.getProperty("os.arch");
        int procs = rt.availableProcessors();

        System.out.println("╔══════════════════════════════════════╗");
        System.out.println("║       JAVA SYSTEM REPORT             ║");
        System.out.println("╠══════════════════════════════════════╣");
        System.out.printf("║ %-14s: %-21s║%n", "OS Name", os);
        System.out.printf("║ %-14s: %-21s║%n", "Architecture", arch);
        System.out.printf("║ %-14s: %-21s║%n", "Processors", procs);
        System.out.printf("║ %-14s: %-18s MB ║%n", "Total Memory", totalMB);
        System.out.printf("║ %-14s: %-18s MB ║%n", "Free Memory", freeMB);
        System.out.printf("║ %-14s: %-18s MB ║%n", "Used Memory", usedMB);
        System.out.println("╚══════════════════════════════════════╝");
    }
}
